// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "${CONTRACT_PATH}";

contract CryptoTest is Test {
    ${CONTRACT_NAME} public target;
    uint256 internal privateKey = 0xBEEF;
    address internal signer;

    function setUp() public {
        target = new ${CONTRACT_NAME}();
        signer = vm.addr(privateKey);
    }

    function testSignatureMalleability() public {
        bytes32 hash = keccak256("test message");
        (uint8 v, bytes32 r, bytes32 s) = vm.sign(privateKey, hash);

        // Create malleable signature by flipping s
        // s' = secp256k1n - s
        uint256 secp256k1n = 0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141;
        bytes32 sMalleable = bytes32(secp256k1n - uint256(s));
        uint8 vMalleable = v == 27 ? 28 : 27;

        // Both signatures should recover to same address if vulnerable
        // Secure contracts reject the malleable one
    }

    function testZeroAddressRecovery() public {
        // Invalid signature that returns address(0)
        bytes32 hash = keccak256("test");
        address recovered = ecrecover(hash, 27, bytes32(0), bytes32(0));
        assertEq(recovered, address(0), "Should return zero");

        // Contract should check for zero address
    }

    function testReplayAttack() public {
        // Use same signature on different chain/contract
        // Should fail if domain separator is used
    }

    function testWeakRandomness() public {
        // Manipulate block values
        vm.roll(12345);
        vm.warp(1234567890);

        // If contract uses block.timestamp or block.number for randomness,
        // attacker can predict/manipulate outcomes
    }

    function testHashCollision() public {
        // abi.encodePacked collision with dynamic types
        bytes memory a = abi.encodePacked("a", "bc");
        bytes memory b = abi.encodePacked("ab", "c");
        assertEq(keccak256(a), keccak256(b), "Collision!");
    }
}
